@ARTICLE{10.3389/fphar.2025.1678663,
	author = {Ding H and Zhang S and Lin L and Zhang K},
	title = {Case Report: Tislelizumab-induced panuveitis: a report of two cases.},
	journal = {Front Pharmacol},
	year = {2025},
	abstract = {BACKGROUND: Tislelizumab, an increasingly utilized immunotherapy for a range of malignancies, can induce a rare ocular immune-related adverse event resembling Vogt-Koyanagi-Harada-like syndrome (VKHLS). Management of complication requires careful balancing with ongoing systemic anti-tumor therapy. CASE PRESENTATION: This report describes two cancer patients who developed severe bilateral vision loss following Tislelizumab treatment. Multimodal ocular imaging confirmed the diagnosis of immune checkpoint inhibitors (ICIs)-associated uveitis, specifically a VKHLS. Both patients were managed with discontinuation of Tislelizumab and local corticosteroid therapy-transcutaneous periocular injection of triamcinolone acetonide (TA) and topical steroid eye drops, without systemic corticosteroids. Their uveitis resolved rapidly, with recovery of visual acuity. CONCLUSION: Prompt Tislelizumab discontinuation combined with local corticosteroid therapy-transcutaneous periocular TA injections, and topical steroid eye drops may constitute an effective management strategy for ICIs-induced uveitis. This approach is particularly valuable for cancer patients in whom systemic corticosteroids are contraindicated or unsuitable.},
	doi = {10.3389/fphar.2025.1678663},
	pmid = {41487505},
	note = {PMC12758019}
}

@ARTICLE{10.1016/j.jare.2025.12.030,
	author = {Wen Y and Zhu L and Huang Z and Zhang G and Tian S and Peng Y and Zhang Y and Wu D and Chen X and Jiang G and Su W and Li H},
	title = {Single-Cell RNA sequencing identifies NAMPT as a potential therapeutic target in autoimmune uveitis.},
	journal = {J Adv Res},
	year = {2025},
	abstract = {INTRODUCTION: Autoimmune uveitis (AU) is an autoimmune disease of the eye that can lead to irreversible vision loss. Current therapies are limited by suboptimal efficacy and substantial side effects, highlighting the urgent need for the discovery of novel therapeutic targets. Nicotinamide phosphoribosyltransferase (NAMPT) is a key enzyme controlling the NAD+ salvage pathway and also exerts immunoregulatory and anti-inflammatory effects. However, its role in AU remains unclear. OBJECTIVE: To investigate NAMPT's effects on AU and underlying mechanisms. METHODS: Single-cell RNA sequencing (scRNA-seq) was performed on cervical draining lymph node (CDLN) cells from normal, experimental autoimmune uveitis (EAU), and NAMPT inhibitor-treated EAU mice. The influence of NAMPT inhibition on immune cell subsets, transcriptional programs, and intercellular communication networks was comprehensively analyzed. Additionally, scRNA-seq was performed on peripheral blood mononuclear cells (PBMCs) collected from Vogt-Koyanagi-Harada (VKH) disease patients and healthy controls (HC) to assess NAMPT expression and its modulation in human CD4+ T cells. In vivo and in vitro experiments, flow cytometry, and adoptive transfer experiments confirmed NAMPT's role in uveitis. RESULTS: NAMPT inhibition significantly ameliorated the clinical and histopathological manifestations of EAU. scRNA-seq revealed that NAMPT blockade reshaped immune cell composition and reversed disease-associated transcriptional programs, particularly within CD4+ T cells. It suppressed pro-inflammatory T helper (Th)-17 and Th1 responses while promoting regulatory T cell (Treg) populations. Mechanistically, NAMPT inhibition modulated the Th17/Treg balance by downregulation of Hif1α expression. In VKH patients, CD4+ T cells exhibited elevated NAMPT expression, which led to increased Th17 and Th1 cells and reduced Tregs. NAMPT knockdown reproduced the protective phenotype observed with FK866 treatment, suggesting a conserved NAMPT-Hif1α axis in human uveitis. CONCLUSIONS: Inhibiting NAMPT can reverse the imbalance of effector T (Teff)/Treg cells by suppressing the expression of Hif1α in CD4+T cells, thereby effectively alleviating the symptoms of EAU. Therefore, NAMPT might be a potential target for AU.},
	doi = {10.1016/j.jare.2025.12.030},
	pmid = {41475661}
}

@ARTICLE{10.3390/ph18121848,
	author = {Lee J and Chung YR and Kim HR and Song JH},
	title = {Efficacy of Tumor Necrosis Factor-α Inhibitor Adalimumab in Chronic Recurrent Vogt-Koyanagi-Harada Disease.},
	journal = {Pharmaceuticals (Basel)},
	year = {2025},
	abstract = {Background/Objectives: Vogt-Koyanagi-Harada (VKH) disease is a bilateral granulomatous panuveitis that can progress to a chronic, relapsing phase. Patients refractory or intolerant to systemic corticosteroids and conventional immunomodulatory therapy pose a major therapeutic challenge, as persistent inflammation can lead to cumulative ocular damage and permanent vision loss. This study assessed the efficacy of tumor necrosis factor-α (TNF-α) inhibitor adalimumab in chronic recurrent VKH disease. Methods: We retrospectively reviewed 16 eyes from 8 patients with chronic recurrent VKH disease who had persistent inflammation despite treatment with corticosteroids and conventional immunomodulatory therapy, and subsequently received adalimumab. Primary outcomes were changes in subfoveal choroidal thickness (SFCT) and systemic corticosteroid dose reduction. Secondary outcomes included visual acuity, inflammatory parameters (anterior chamber cell, flare, and vitreous haze), and central macular thickness (CMT). All outcomes were compared between baseline and 6 months after adalimumab initiation using the Wilcoxon signed-rank test. Results: Mean patient age was 47.6 years and mean follow-up was 31.8 months. SFCT decreased from 326.7 ± 129.1 μm to 231.6 ± 72.9 μm at 6 months (p < 0.001). Systemic steroid dose decreased from 14.7 ± 14.0 mg to 4.1 ± 3.8 mg (p = 0.027). Mean annualized relapse rate decreased from 3.61 to 0.08 episodes/year (p = 0.012). Anterior chamber cell grade decreased from 0.81 ± 0.66 to 0.09 ± 0.20 (p < 0.001). Visual acuity, flare, vitreous haze, and CMT showed no significant change. No serious adverse events occurred. Conclusions: TNF-α inhibition with adalimumab appears effective as steroid-sparing therapy for controlling recurrent inflammation and reducing steroid dependence in patients with chronic recurrent VKH disease refractory to conventional treatment.},
	doi = {10.3390/ph18121848},
	pmid = {41471337},
	note = {PMC12736142}
}

@ARTICLE{10.3389/fimmu.2025.1689498,
	author = {Li P and Wang Q and Yang Y and Ding Z},
	title = {Autoimmune thyroid disease and human health: a systematic review of Mendelian randomization studies.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {We systematically summarized current Mendelian randomization (MR) evidence on the causal relationships between autoimmune thyroid disease (AITD) and a wide range of human health outcomes. Original MR studies related to AITD published up to March 1, 2025, were retrieved from PubMed and Embase. For studies investigating the same exposure-outcome associations, meta-analyses were performed to synthesize the evidence after excluding overlapping samples where applicable. The methodological quality of the included studies was assessed using the STROBE-MR checklist. A total of 123 MR publications met the inclusion criteria. MR analyses indicated that AITD significantly increased the risk of coronary atherosclerosis, deep venous thrombosis, chronic obstructive pulmonary disease, major depression, diabetic neuropathy, carpal tunnel syndrome, neuromyelitis optica spectrum disorder, diabetic retinopathy, childhood absence epilepsy, rheumatoid arthritis, systemic lupus erythematosus, psoriatic arthritis, inflammatory bowel disease, crohn's disease, vitiligo, myasthenia gravis, alopecia areata, type 1 and type 2 diabetes, sarcoidosis, frozen shoulder, drug eruptions, cataract, early age-related macular degeneration, pernicious anemia, Helicobacter pylori infection, temporomandibular disorders, migraine, frailty, primary biliary cholangitis, knee osteoarthritis, gout, and osteoporosis, while decreasing the risk of lung cancer, polyneuropathies, allergic rhinitis, telomere length, and serum vitamin A levels. The included MR studies were of high methodological quality and provided robust evidence supporting the bidirectional relationships between AITD and various health outcomes. These findings emphasize the importance and necessity of preventing and managing AITD while offering new perspectives and directions for future research on its prevention and treatment. SYSTEMATIC REVIEW REGISTRATION: https://www.crd.york.ac.uk/prospero/, identifier CRD42023469038.},
	doi = {10.3389/fimmu.2025.1689498},
	pmid = {41425574 [Indexed for MEDLINE]},
	note = {PMC12711731}
}

@ARTICLE{10.1002/art.70022,
	author = {Li BM and Hung JH and Yang PC and Lin SJ and Lai EC and Weng MY},
	title = {Weighing Dose-Related Benefits and Risks of Hydroxychloroquine Treatment in Patients With Systemic Lupus Erythematosus.},
	journal = {Arthritis Rheumatol},
	year = {2025},
	abstract = {OBJECTIVE: To weigh higher-dose hydroxychloroquine (HCQ; ≥400 mg/day) and lower-dose HCQ (<400 mg/day) for effectiveness and safety among patients with systemic lupus erythematosus (SLE). METHODS: This nationwide study retrieved data from Taiwan's National Health Insurance Research Database from 2010 to 2021. We included patients with SLE aged over 10 years and initiating HCQ who had no other systemic autoimmune disease at baseline and no historical outcomes of interest. Patients were classified into higher-dose (≥400 mg/day) or lower-dose (<400 mg/day) treatment strategies based on the dosage of their first HCQ prescription. The outcomes were coronary artery disease (CAD), ischemic stroke, venous thromboembolism (VTE), end-stage renal disease, malignancy, and HCQ retinopathy. RESULTS: Eight hundred seventy-eight (3.77%) patients taking higher-dose HCQ and 22,405 (96.22%) taking lower-dose HCQ were included. After inverse probability weighting, higher-dose HCQ was associated with lower risks of CAD (hazard ratio [HR] 0.86, 95% confidence interval [CI] 0.80-0.93) and VTE (HR 0.40, 95% CI 0.33-0.49). We found no dose-related difference in the risk of ischemic stroke, end-stage renal disease, malignancy, and HCQ retinopathy through a mean follow-up of six years, except for the HCQ retinopathy among patients with SLE aged over 45 years (HR 1.87, 95% CI 1.45-2.42). CONCLUSION: For patients with SLE, higher-dose HCQ improves effectiveness, with reduced risks of CAD and VTE. There was no dose-related difference in the risk of HCQ retinopathy for patients with SLE aged younger than 45 years. Our study emphasizes the need for weighing the benefits and risks of optimal HCQ dosage in managing SLE.},
	doi = {10.1002/art.70022},
	pmid = {41423344}
}

@ARTICLE{10.14336/AD.2025.1221,
	author = {Ma H and Li S and Le Y and Stanford D and Freeman WM and Ding XQ},
	title = {Single Cell RNAseq Analysis of Thyroid Hormone Effects on Retinal Glial Cells.},
	journal = {Aging Dis},
	year = {2025},
	abstract = {Thyroid hormone (TH) signaling regulates cellular metabolism and stress response in the retina. Increased TH levels in circulation are associated with a higher incidence of age-related macular degeneration. Furthermore, stimulation of TH signaling induces retinal degeneration in mice, which is accompanied by the activation of retinal glial cells. Here, we investigated the transcriptional changes induced by triiodothyronine (T3) in retinal glial cells using single-cell RNA sequencing (scRNAseq) and bioinformatic analyses. One-month-old C57BL/6 mice were given T3 (20 μg/ml in drinking water) for four weeks, after which their retinal cells were collected to assess viability and undergo scRNAseq. The resulting data were analyzed using the Seurat package, visualized by the Loupe Browser, and Ingenuity Pathway Analysis. Analyses of differentially expressed genes (DEGs) in Müller cells, astrocytes, and microglia revealed significant enrichment in pathways associated with stress, immune response, and degeneration. Müller cells exhibited upregulation of mitochondrial dysfunction, acute-phase response, and sirtuin signaling pathways. Astrocytes displayed downregulation of synaptogenesis, neurovascular coupling, cAMP response elements, and calcium signaling. Microglia showed upregulation of coordinated lysosomal expression and regulation signaling, systemic lupus erythematosus in T cells, and multiple sclerosis signaling, and downregulation of actin-binding Rho activating signaling, retinoic acid receptor activation signaling, and IL-17 signaling. The distinct and overlapping transcriptional responses suggest that each retinal glial cell type plays a specific and coordinated role in adapting to stress. This study offers new insights into TH-induced retinal stress and degeneration at the transcriptional and pathway-level responses of retinal glial cells.},
	doi = {10.14336/AD.2025.1221},
	pmid = {41400582}
}

@ARTICLE{10.3390/ijms262311744,
	author = {Luboń W, Luboń M, Agaś-Lange A and Dorecka M},
	title = {Systemic Lupus Erythematosus: Ophthalmological Safety Considerations of Emerging and Conventional Therapeutic Agents.},
	journal = {Int J Mol Sci},
	year = {2025},
	abstract = {Systemic lupus erythematosus (SLE) is a chronic multisystem autoimmune disorder in which ocular involvement represents a clinically significant yet frequently underrecognized contributor to morbidity. Ocular manifestations in SLE may arise from disease activity itself, but also as adverse effects of long-term pharmacological therapy. With the advent of targeted immunomodulatory agents, the therapeutic landscape of SLE has expanded beyond conventional drugs such as hydroxychloroquine and corticosteroids toward biologics and small molecules designed to interfere with specific immunological pathways. These advances have improved systemic disease control and survival; however, their ophthalmological safety profiles remain only partially defined. This review synthesizes current evidence on ocular adverse events associated with both traditional and emerging SLE therapies. Established agents, particularly hydroxychloroquine and corticosteroids, are consistently linked to complications including retinopathy, posterior subcapsular cataracts, steroid-induced glaucoma, and central serous chorioretinopathy. In contrast, recently approved or investigational therapies-such as belimumab, anifrolumab, voclosporin, dual BAFF/APRIL inhibitors, rituximab, JAK inhibitors, CD40/CD40L blockade, CD38 inhibition, and mesenchymal stromal cell-based strategies-have limited but evolving safety data, with potential ocular adverse events spanning inflammatory, vascular, neuro-ophthalmic, and structural domains. Although ocular complications appear infrequent in clinical trials, underdetection in real-world practice and insufficient long-term monitoring may underestimate their true incidence. These findings highlight the need for systematic ophthalmological surveillance in patients receiving immunomodulatory therapies for SLE. Early recognition and timely management of ocular toxicity are crucial to safeguarding visual function and optimizing long-term therapeutic outcomes in this vulnerable patient population.},
	doi = {10.3390/ijms262311744},
	pmid = {41373894 [Indexed for MEDLINE]},
	note = {PMC12693600}
}

@ARTICLE{10.1093/brain/awaf458,
	author = {Akada M and Hata M and Miyake M and Ishihara K and Muraoka Y and Morooka S and Tamura H and Tsujikawa A},
	title = {Natural experiment on neuroinflammatory disease incidence and infection links pre- and post-COVID-19.},
	journal = {Brain},
	year = {2026},
	abstract = {Infections are recognized triggers for several neuroinflammatory disorders. The coronavirus disease 2019 (COVID-19) pandemic's non-pharmaceutical interventions sharply curtailed pathogen exposure, creating a natural experiment to test infection-disease links. Using Japan's National Claims Database, we first validated the nationwide decline with two strictly infection-dependent conditions-epidemic keratoconjunctivitis and influenza-associated encephalopathy-whose monthly incidences fell by >60% after April 2020. Next, we applied an interrupted time series design, a causal-inference method for longitudinal data, to nine immune-mediated inflammatory diseases. Unsupervised clustering of model-derived level and slope changes identified three data-driven clusters. The first cluster, comprising Guillain-Barré syndrome and acute disseminated encephalomyelitis, showed large, statistically significant level reductions (P < 0.001), particularly in women, consistent with infection-susceptible pathophysiology. The second cluster, including myasthenia gravis and optic neuritis, exhibited transient declines followed by significant positive post-intervention slopes (P < 0.001), suggesting deferred diagnosis, treatment interruption or immune rebound. The third cluster, consisting of sarcoidosis, neuromyelitis optica, multiple sclerosis, Vogt-Koyanagi-Harada disease and Behçet's disease, remained stable, suggesting limited or complex infectious links. These data-driven trajectories mirror clinical pathophysiology and demonstrate that reduced pathogen exposure affects neuroinflammatory disease onset to varying degrees. This framework supports infection-related risk stratification, preventive strategies and continuity planning in neuroimmunology practice.},
	doi = {10.1093/brain/awaf458},
	pmid = {41359492 [Indexed for MEDLINE]}
}

@ARTICLE{10.1186/s13040-025-00499-w,
	author = {Basharat Z and Ogaly HA and Al-Zahrani FAM and Wei CR and Hassan SS and Salman M and Islam M and Ahmed I and Waheed Y and Kim S},
	title = {Bioinformatics analysis of Rickettsia typhi autoimmune associations and screening of Streptomyces-derived inhibitors.},
	journal = {BioData Min},
	year = {2025},
	abstract = {BACKGROUND: Rickettsia typhi is the causative agent of epidemic murine typhus and Rocky Mountain spotted fever. The infection can affect multiple vital organs, including the heart, lungs, kidneys, and brain. Doxycycline is the recommended treatment but inflammation, mal-response, and drug resistance may arise. No natural product inhibitors have been reported against this bacterium. AIM: The objective of this study was to establish a potential connection between autoimmune disorders triggered by R. typhi, identify therapeutic targets within its core proteome, and explore novel natural product inhibitors from Streptomyces spp. that could potentially inhibit it. METHODOLOGY: Complete proteomes of four publicly available R. typhi strains were used for pan-proteomic analysis. The fni gene product (Isopentenyl pyrophosphate isomerase) was selected as the potential drug target. Molecular docking of 607 Streptomyces-derived metabolites was performed, with top hits validated using DiffDock and Vinardo scoring. Additionally, the Absorption, Distribution, Metabolism, Excretion, and Toxicity properties of the leading compounds were assessed via pkCSM, and formulation characteristics optimized using FormulationAI. RESULTS: Out of the 803 core proteins, associations between 14 proteins were mined for autoimmune diseases (including psoriasis, rheumatoid arthritis, optic atrophy, uveitis, even-plus syndrome, Sjogren syndrome, inflammatory bowel disease, allergic rhinitis, systemic lupus erythematosus, sclerosis, Stevens-Johnson syndrome, toxic epidermal necrolysis, colitis etc.). 17 core proteins were predicted as druggable. ZINC01482946 demonstrated the strongest inhibitory potential, as confirmed by DiffDock scoring, convolutional neural network-based ranking, and Vinardo scoring. It demonstrated a stable configuration and exhibited a favorable pharmacokinetic profile, with bioavailability enhanced through cyclodextrin complexation. CONCLUSION: To the best of our knowledge, this is the first report identifying human autoimmune associations with R. typhi and natural product inhibitors targeting the pathogen. ZINC01482946 shows potential as an effective inhibitor of R. typhi, while SBE-β-CD appears to be a promising cyclodextrin for improving its solubility and bioavailability. CLINICAL TRIAL NUMBER: Not applicable.},
	doi = {10.1186/s13040-025-00499-w},
	pmid = {41316447},
	note = {PMC12661794}
}

@ARTICLE{10.1016/j.ijbiomac.2025.149013,
	author = {Sijilmassi O},
	title = {Collagen IV and laminin-1 as key macromolecules in ocular structure and pathology: A review.},
	journal = {Int J Biol Macromol},
	year = {2025},
	abstract = {The extracellular matrix (ECM), particularly the basement membrane (BM), is critical for the structural organization and functionality of ocular tissues. Among its core components, type IV collagen and laminin-1 play central roles in cell adhesion, polarity, differentiation, and survival. These macromolecules are ubiquitously expressed in the cornea, lens, retina, and optic nerve, forming tissue-specific BMs that support development and homeostasis. In this review, findings on the spatial distribution and molecular roles of collagen IV and laminin-1 in the eye under physiological and pathological conditions, are summarized. Mutations in COL4A1, COL4A2, and laminin-encoding genes (LAMA1, LAMB1, LAMC1) are associated with a range of ocular disorders, including anterior segment dysgenesis, lens dystrophy, optic nerve hypoplasia, and retinal abnormalities. Furthermore, autoimmune responses targeting these BM proteins have been implicated in systemic diseases such as rheumatoid arthritis, systemic lupus erythematosus, systemic sclerosis, and Sjögren's syndrome, often leading to serious ocular complications. This review emphasizes the importance of ECM macromolecules in maintaining ocular integrity and highlights their potential as diagnostic biomarkers and therapeutic targets in both inherited and immune-mediated eye diseases.},
	doi = {10.1016/j.ijbiomac.2025.149013},
	pmid = {41237879 [Indexed for MEDLINE]}
}
